"crm.formula.tonumberdesc": "\uc22b\uc790\ub85c\ub9cc \uad6c\uc131\ub41c \ubb38\uc790\uc5f4\uc744 \uc218\uce58 \ubcc0\uc218\ub85c \ubcc0\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc37": "\ub450 \ub0a0\uc9dc \uac04\uc758 \uc2dc\uac04 \ucc28\uc774(\ubd84)\ub97c \ubc18\ud658\ud569\ub2c8\ub2e4. \uccab \ubc88\uc9f8 \ub0a0\uc9dc\uac00 \ub450 \ubc88\uc9f8 \ub0a0\uc9dc\ubcf4\ub2e4 \ub098\uc911\uc774\uba74 \uacb0\uacfc\ub294 \uc591\uc218\uc785\ub2c8\ub2e4. \uadf8 \ubc16\uc758 \uacbd\uc6b0 \uacb0\uacfc\ub294 \uc74c\uc218\uc785\ub2c8\ub2e4.",
"crm.formula.desc36": "\ud604\uc7ac \ub0a0\uc9dc \ubc0f \uc2dc\uac04\uc744 \ubc18\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc35": "\uc8fc\uc5b4\uc9c4 \ub0a0\uc9dc\uc5d0\uc11c n(\uc5f0\ub3c4/\uc77c/\uc6d4/\uc2dc\uac04/\ubd84)\uc744 \ucc28\uac10\ud558\uc5ec \uc5bb\uc740 \ub0a0\uc9dc\ub97c \ubc18\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc34": "\uc8fc\uc5b4\uc9c4 \ub0a0\uc9dc\uc5d0 n(\uc5f0\ub3c4/\uc77c/\uc6d4/\uc2dc\uac04/\ubd84)\uc744 \ub354\ud558\uc5ec \uc5bb\uc740 \ub0a0\uc9dc\ub97c \ubc18\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc33": "\ub0a0\uc9dc \uc2dc\uac04 \ud45c\ud604\uc2dd\uc758 \uc2dc\uac04\ub9cc \ubc18\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc32": "\ub0a0\uc9dc \uc2dc\uac04 \ud45c\ud604\uc2dd\uc758 \ub0a0\uc9dc\ub9cc \ubc18\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc31": "\uc5f0\ub3c4, \uc6d4, \uc77c \ubc0f \uc2dc\uac04\uc73c\ub85c \ub0a0\uc9dc\ub97c \uc0dd\uc131\ud569\ub2c8\ub2e4.",
"crm.formula.desc30": "\uc785\ub825 \ubb38\uc790\uc5f4\uc5d0\uc11c \uac80\uc0c9 \ubb38\uc790\uc5f4\uc774 \ub098\uc62c \ub54c\ub9c8\ub2e4 \ub300\uccb4 \ubb38\uc790\uc5f4\ub85c \ubcc0\uacbd\ud569\ub2c8\ub2e4.",
"crm.formula.desc29": "\ubaa8\ub4e0 \uc778\uc218\ub97c \ubb38\uc790\uc5f4 \ub370\uc774\ud130 \uc720\ud615\uc73c\ub85c \ubcc0\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc28": "\uc9c0\uc815 \uae38\uc774\uc5d0 \ub530\ub77c \ubb38\uc790\uc5f4\uc758 \uc2dc\uc791 \uc9c0\uc810\ubd80\ud130 \uc785\ub825 \ubb38\uc790\uc5f4\uc758 \uc77c\ubd80\ub97c \ubc18\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc27": "\ubb38\uc790\uc5f4 \uc55e\ub4a4\uc758 \uacf5\ubc31\uc744 \uc81c\uac70\ud569\ub2c8\ub2e4.",
"crm.formula.desc26": "\uc785\ub825 \ubb38\uc790\uc5f4\uc758 \ubaa8\ub4e0 \uae00\uc790\ub97c \ub300\ubb38\uc790\ub85c \ubcc0\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc25": "\uc785\ub825 \ubb38\uc790\uc5f4\uc758 \ubaa8\ub4e0 \uae00\uc790\ub97c \uc18c\ubb38\uc790\ub85c \ubcc0\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc24": "\ubb38\uc790\uc5f4\uc774 \uac80\uc0c9 \ubb38\uc790\uc5f4\ub85c \ub05d\ub098\uba74 \u201ctrue\u201d\ub97c, \uadf8\ub807\uc9c0 \uc54a\uc73c\uba74 \u201cfalse\u201d\ub97c \ubc18\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc23": "\ubb38\uc790\uc5f4\uc774 \uac80\uc0c9 \ubb38\uc790\uc5f4\ub85c \uc2dc\uc791\ub418\uba74 \u201ctrue\u201d\ub97c, \uadf8\ub807\uc9c0 \uc54a\uc73c\uba74 \u201cfalse\u201d\ub97c \ubc18\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc22": "\ubb38\uc790\uc5f4 2\uc5d0 \ubb38\uc790\uc5f4 1\uc774 \uc788\uc73c\uba74 true\ub97c, \uc5c6\uc73c\uba74 false\ub97c \ubc18\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc21": "\ubaa8\ub4e0 \ubb38\uc790\uc5f4\uc758 \uc5f0\uacb0 \uac12\uc744 \ubc18\ud658\ud569\ub2c8\ub2e4. (\uc608: \u201cmay\u201d\uc640 \u201cday\u201d\ub97c \uc5f0\uacb0\ud558\uba74 \u201cmayday\u201d)",
"crm.formula.desc20": "\ud2b9\uc815 \ud45c\ud604\uc2dd\uc758 \ub17c\ub9ac \ubd80\uc815\uc744 \ubc18\ud658\ud569\ub2c8\ub2e4 (\uc608: \ud45c\ud604\uc2dd\uc774 true\uc774\uba74 false \ubc18\ud658).",
"crm.formula.desc19": "\ucc38\uc778 \ud45c\ud604\uc2dd\uc774 \uc788\uc73c\uba74 \u201ctrue\u201d\ub97c \ubc18\ud658\ud569\ub2c8\ub2e4. \ubaa8\ub4e0 \ud45c\ud604\uc2dd\uc774 \uac70\uc9d3\uc774\uba74 false\ub97c \ubc18\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc18": "\ubaa8\ub4e0 \uc218\uc2dd\uc774 true\uc774\uba74 \u201ctrue\u201d\ub97c, \ud558\ub098 \uc774\uc0c1\uc758 \uc218\uc2dd\uc774 false\uc774\uba74 \u201cfalse\u201d\ub97c \ubc18\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc17": "\uc785\ub825 \ub0a0\uc9dc\uc5d0 \ud574\ub2f9\ud558\ub294 \uc694\uc77c(1-7)\uc744 \ubc18\ud658\ud569\ub2c8\ub2e4. 1\uc740 \uc77c\uc694\uc77c, 2\ub294 \uc6d4\uc694\uc77c\uc774 \ub418\ub294 \ubc29\uc2dd\uc785\ub2c8\ub2e4. (\uc608: Friday\ub294 \u201c6\u201d \ubc18\ud658)",
"crm.formula.desc16": "\ud2b9\uc815\uc77c\uc758 \uc5f0\ub3c4\ub97c \ubc18\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc15": "\ud2b9\uc815\uc77c\uc758 \uc6d4\uc5d0 \ud574\ub2f9\ud558\ub294 \uc22b\uc790\ub97c \ubc18\ud658\ud569\ub2c8\ub2e4. (\uc608: April 5th\ub294 \u201c4\u201d \ubc18\ud658)",
"crm.formula.desc14": "\ud2b9\uc815 \uc2dc\uac04\uc5d0 \ud574\ub2f9\ud558\ub294 \ubd84\uc744 \ubc18\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc13": "\ud2b9\uc815 \uc2dc\uac04\uc5d0 \uc2dc(24\uc2dc \ud615\uc2dd)\ub97c \ubc18\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc12": "\ud2b9\uc815\uc77c\uc758 \ub0a0\uc9dc\uc5d0 \ud574\ub2f9\ud558\ub294 \uc22b\uc790\ub97c \ubc18\ud658\ud569\ub2c8\ub2e4. (\uc608: April 5th\ub294 \u201c5\u201d \ubc18\ud658)",
"crm.formula.desc11": "\ubb38\uc790\uc5f4 \uc548\uc5d0\uc11c \uac80\uc0c9 \ubb38\uc790\uc758 \uc790\ub9ac \ubc88\ud638\ub97c \ubc18\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc10": "\uc9c0\uc815\ud55c \ud14d\uc2a4\ud2b8 \ubb38\uc790\uc5f4\uc758 \ubb38\uc790 \uac1c\uc218\ub97c \ubc18\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc9": "\ub17c\ub9ac \uc870\uac74\uc5d0 \ub530\ub77c \ub450 \uac12 \uc911 \ud558\ub098\ub97c \ubc18\ud658\ud569\ub2c8\ub2e4. \ubd80\uc6b8 \ud14c\uc2a4\ud2b8\uac00 true\uc774\uba74 \uc0ac\uc6a9\uc790 \uc9c0\uc815 \ud544\ub4dc\ub294 \u201ctrue\u201d\ub97c, \ubd80\uc6b8 \ud14c\uc2a4\ud2b8\uac00 false\uc774\uba74 \uc0ac\uc6a9\uc790 \uc9c0\uc815 \ud544\ub4dc\uac00 \u201cfalse\u201d\ub97c \ubc18\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc8": "\uc22b\uc790\uc758 \uc81c\uacf1\uadfc\uc744 \ubc18\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc7": "\uc9c0\uc815\ud55c \uc22b\uc790 \ubaa9\ub85d\uc758 \ucd5c\uc18c \uac12\uc744 \ubc18\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc6": "\uc9c0\uc815\ud55c \uc22b\uc790 \ubaa9\ub85d\uc758 \ucd5c\ub300 \uac12\uc744 \ubc18\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc5": "\uc785\ub825\ud55c \uc218\uc5d0 \ub300\ud574 \ubc11\uc774 10\uc778 \ub85c\uadf8 \uac12\uc744 \ubc18\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc4": "\uc785\ub825\ud55c \uc218\uc758 \uc790\uc5f0 \ub85c\uadf8\ub97c \ubc18\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc3": "\uc785\ub825\ud55c \uc22b\uc790 \uc774\ud558\uc778 \uac00\uc7a5 \ud070 \uc815\uc218\ub97c \ubc18\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc2": "\uc785\ub825\ud55c \uc22b\uc790 \uc774\uc0c1\uc778 \uac00\uc7a5 \uc791\uc740 \uc815\uc218\ub97c \ubc18\ud658\ud569\ub2c8\ub2e4.",
"crm.formula.desc1": "\uc22b\uc790\uc758 \uc808\ub300\uac12\uc744 \ubc18\ud658\ud569\ub2c8\ub2e4.",
